 import sailpoint.object.*;
 import sailpoint.api.*;
 import java.time.LocalDate;
 import java.util.Date;
 import java.text.SimpleDateFormat;
 import java.time.Instant;
 import java.time.temporal.ChronoUnit;
 import java.util.TimeZone;
 import sailpoint.tools.Util;
 import org.apache.log4j.Logger; 
 import org.apache.log4j.Level;
 import org.apache.commons.logging.LogFactory;

 Logger wboLog = Logger.getLogger("rule.eshiam.WebServiceBeforeOp1045");
 wboLog.trace("EWBO-001: Executing  rule.eshiam.WebServiceBeforeOp1045");

 wboLog.trace("EWBO-002: requestEndPoint .."+requestEndPoint);

 // Get or create request body
 Map requestBody = requestEndPoint.getBody();
 if (requestBody == null) {
   requestBody = new HashMap();
 }

 String jSonBody = "";
 String operationType = requestEndPoint.getOperationType();

 Date now = new Date();
 SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss");
 sdf.setTimeZone(TimeZone.getTimeZone("UTC"));

 // Format current system date in UTC
 String currentDate = sdf.format(new Date(now.getTime()))+"Z";
 String acctAggregationEnd = sdf.format(application.getAttributeValue("acctAggregationEnd"))+"Z";
 String futureDate =  sdf.format(new Date(now.getTime()+10*24*60*60*1000L))+"Z";
 String terminationDate =  sdf.format(new Date(now.getTime()-180*24*60*60*1000L))+"Z";


 // Get or create jsonBody
 if (requestBody != null) {
   jSonBody =requestBody.get("jsonBody");
 }

 // Convert lastAggregationDate into the ISO UTC format
 String acctAggregationEnd = sdf.format(lastAggregationDate);
 if(acctAggregationEnd == null){
   acctAggregationEnd = sdf.format(new Date(now.getTime()-1*60*60*1000))+"Z";
 }
// wboLog.trace("EWBO-003: terminationDate  futureDate  acctAggregationEnd  currentDate ..  "+terminationDate+"   "+futureDate+"    "+acctAggregationEnd+"    "+currentDate);
 // Replace placeholders in JSON body
 jSonBody =  jSonBody.replaceAll("currentDate", currentDate);
 jSonBody =  jSonBody.replaceAll("lastAggregationDate", acctAggregationEnd);
 jSonBody =  jSonBody.replaceAll("terminationDate", terminationDate);
 jSonBody = jSonBody.replaceAll("hireDate", futureDate);

 // Update request body with modified JSON
 requestBody.put("jsonBody", jSonBody);
 requestEndPoint.setBody(requestBody);

 wboLog.trace("EWBO-004: requestEndPoint at the end of rule .."+requestEndPoint);

 return requestEndPoint;
